(function injectTasksListDefault() {
  const a = process.argv;
  const i = a.indexOf('tasks');
  if (i === -1) return;
  const first = a[i + 1];
  const known = new Set(['list', 'claim', 'release', 'active']);
  if (first === undefined || first.startsWith('-')) {
    a.splice(i + 1, 0, 'list');
