/**
 * Resolve the monorepo root from forge's location.
 *
 * In `next dev` / `next build` the process cwd is `apps/forge/`. Tracing
 * root in next.config.mjs points at `../../` (the monorepo). We do the same
 * resolution here with a fallback to walking up looking for pnpm-workspace.yaml
 * in case the app is ever run from a different cwd.
 */
function resolveMonorepoRoot(): string {
  const cwd = process.cwd();
  // Fast path: forge dev/build runs from apps/forge/.
  const direct = path.resolve(cwd, "..", "..");
  if (fs.existsSync(path.join(direct, "pnpm-workspace.yaml"))) {
    return direct;
  }
  // Walk up until we find pnpm-workspace.yaml.
  let cur = cwd;
  for (let i = 0; i < 8; i += 1) {
    if (fs.existsSync(path.join(cur, "pnpm-workspace.yaml"))) return cur;
    const parent = path.dirname(cur);
    if (parent === cur) break;
    cur = parent;
  }
  // Fall back — non-fatal, caller will just see no generations.
  return direct;
}

