import { getGenerations, type Generation } from "@/lib/generations";

function formatRelative(date: Date): string {
  const now = Date.now();
  const diffMs = now - date.getTime();
  const sec = Math.round(diffMs / 1000);
  if (sec < 60) return `${sec}s ago`;
  const min = Math.round(sec / 60);
  if (min < 60) return `${min}m ago`;
  const hr = Math.round(min / 60);
  if (hr < 48) return `${hr}h ago`;
  const d = Math.round(hr / 24);
  if (d < 60) return `${d}d ago`;
  const mo = Math.round(d / 30);
  if (mo < 24) return `${mo}mo ago`;
  const yr = Math.round(d / 365);
  return `${yr}y ago`;
}

function GenerationCard({ g }: { g: Generation }) {
  const href = `/g/${encodeURIComponent(g.project)}/${encodeURIComponent(g.species)}/${encodeURIComponent(g.version)}`;
  return (
    <Link
      href={href}
      className="block rounded-lg border border-[var(--border)] bg-[var(--card)] p-5 transition-colors hover:border-[var(--accent)]"
    >
      <div className="flex items-baseline justify-between gap-3">
        <h2 className="text-xl font-semibold tracking-tight text-white">
          {g.project}
        </h2>
        <span className="rounded-md border border-[var(--border)] px-2 py-0.5 text-xs uppercase tracking-wide text-[var(--muted)]">
          {g.species}
        </span>
      </div>
      <div className="mt-1 flex items-baseline gap-2 text-sm">
        <span className="font-mono text-[var(--accent)]">{g.version}</span>
        <span className="text-[var(--muted)]">·</span>
        <span
          className="text-[var(--muted)]"
          title={g.createdAt.toISOString()}
        >
          {formatRelative(g.createdAt)} (approx)
        </span>
      </div>
      <div
        className="mt-3 truncate font-mono text-xs text-[var(--muted)]"
        title={g.worktreePath}
      >
        {g.worktreePath}
      </div>
      {g.lineageParent ? (
        <div className="mt-2 text-xs text-[var(--muted)]">
          lineage: {g.lineageParent.project}/{g.lineageParent.species}/
          {g.lineageParent.version}
        </div>
      ) : null}
    </Link>
  );
}

export default async function Page() {
  const generations = await getGenerations();

  return (
    <main className="mx-auto max-w-6xl px-6 py-12">
      <header className="mb-8">
        <h1 className="text-3xl font-semibold tracking-tight text-white">
          Generations
        </h1>
        <p className="mt-2 text-sm text-[var(--muted)]">
          {generations.length === 0
            ? "No generations discovered yet."
            : `${generations.length} generation${generations.length === 1 ? "" : "s"} discovered across all eval roots.`}
        </p>
      </header>

      {generations.length === 0 ? (
        <div className="rounded-lg border border-dashed border-[var(--border)] p-8 text-center text-sm text-[var(--muted)]">
          No generations found in{" "}
          <code className="text-[var(--foreground)]">evals/</code>. Run{" "}
          <code className="text-[var(--foreground)]">gad eval list</code> to
          verify, or add a generation under{" "}
          <code className="text-[var(--foreground)]">
            evals/&lt;project&gt;/species/&lt;species&gt;/v&lt;N&gt;/
          </code>
          .
        </div>
      ) : (
        <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-3">
          {generations.map((g) => (
            <GenerationCard
              key={`${g.project}/${g.species}/${g.version}`}
              g={g}
            />
          ))}
        </div>
      )}
    </main>
  );
}
