// -------------------------------------------------------------------------
// Task 44-30: Emit lib/project-config.generated.ts — build-time snapshot of
// all registered GAD projects (planning.roots ∪ evals.roots) from the nearest
// gad-config.toml walking upward from REPO_ROOT. Consumed by the site project
// picker and server-side route scoping. Static; no runtime toml parsing.
// -------------------------------------------------------------------------
function collectRegisteredProjects() {
  let planningRoots = [];
  let evalsRoots = [];
  let sourceConfigPath = null;
  let dir = REPO_ROOT;
  for (let i = 0; i < 8; i += 1) {
    try {
      const cfg = gadConfig.load(dir);
      if (cfg && ((Array.isArray(cfg.roots) && cfg.roots.length > 0) ||
                  (Array.isArray(cfg.evalsRoots) && cfg.evalsRoots.length > 0))) {
        planningRoots = Array.isArray(cfg.roots) ? cfg.roots.filter((r) => r && r.enabled !== false && r.id) : [];
        evalsRoots = Array.isArray(cfg.evalsRoots) ? cfg.evalsRoots.filter((r) => r && r.enabled !== false && r.id) : [];
        sourceConfigPath = cfg.configPath || null;
        break;
      }
    } catch {}
    const parent = path.dirname(dir);
    if (parent === dir) break;
    dir = parent;
  }

  const byId = new Map();
  const configBaseDir = sourceConfigPath ? path.dirname(sourceConfigPath) : REPO_ROOT;
  const resolveRootPath = (p) => {
    if (!p) return configBaseDir;
    return path.isAbsolute(p) ? p : path.resolve(configBaseDir, p);
  };
  for (const r of planningRoots) {
    byId.set(r.id, { id: r.id, kind: "planning", path: resolveRootPath(r.path) });
  }
  for (const r of evalsRoots) {
    const existing = byId.get(r.id);
    if (existing) {
      existing.kind = "both";
    } else {
      byId.set(r.id, { id: r.id, kind: "evals", path: resolveRootPath(r.path) });
    }
  }
  // Fallback: ensure the framework itself is always registered.
  if (!byId.has("get-anything-done")) {
    byId.set("get-anything-done", {
      id: "get-anything-done",
      kind: "planning",
      path: REPO_ROOT,
    });
  }
  const registered = Array.from(byId.values());
  const defaultId = planningRoots[0]?.id || "get-anything-done";
  return { registered, defaultId };
}

function writeProjectConfigTs() {
  const { registered, defaultId } = collectRegisteredProjects();
